botsCount = 0; // Base case.\n\n    long long windowTotalCost = 0;\n\n    int startIdx = 0;\n    deque<pair<int, int>> queue; // Format: {charge time, idx}.\n\n    for (int endIdx = 0; endIdx < chargeTimes.size(); endIdx++)\n    {\n        windowTotalCost += runningCosts[endIdx];\n\n        while (!queue.empty() && queue.back().first <= chargeTimes[endIdx])\n            queue.pop_back();\n\n        queue.push_back({chargeTimes[endIdx], endIdx});\n\n        int robotsCount = endIdx + 1 - startIdx;\n        int maxChargeTime = queue.front().first;\n\n        while (budget < maxChargeTime + robotsCount * windowTotalCost)\n        {\n            windowTotalCost -= runningCosts[startIdx];\n\n            startIdx++;\n            robotsCount--;\n\n            if (!queue.empty() && queue.front().second < startIdx)\n                queue.pop_front();\n\n            if (startIdx > endIdx)\n                break; // 0 robots at hand.\n        }\n\n        if (robotsCount > maxRobotsCount)\n            maxRobotsCount = robotsCount;\n    }\n\n    return maxRobotsCount;\n}\n"})}),(0,t.jsx)(d.A,{value:"python",label:"Python",default:!0,children:(0,t.jsx)(l.A,{language:"python",children:"from collections import deque\n\n\ndef count_max_robots(charge_times: list[int], running_costs: list[int], budget: int):  # LeetCode Q.2398.\n    max_robots_count = 0  # Base case.\n\n    window_total_cost = 0\n\n    queue: deque[tuple[int, int]] = deque([])  # Format: (charge time, idx).\n\n    start_idx = 0\n    for end_idx, charge_time in enumerate(charge_times):\n        window_total_cost += running_costs[end_idx]\n\n        while queue and queue[-1][0] <= charge_time:\n            queue.pop()\n\n        queue.append((charge_time, end_idx))\n\n        robots_count = end_idx + 1 - start_idx\n        max_charge_time = queue[0][0]\n\n        while budget < max_charge_time + robots_count * window_total_cost:\n            window_total_cost -= running_costs[start_idx]\n\n            robots_count -= 1\n            start_idx += 1\n\n            if queue and queue[0][1] < start_idx: queue.popleft()\n\n            if start_idx > end_idx: break  # 0 robots at hand.\n\n        if robots_count > max_robots_count: max_robots_count = robots_count\n\n    return max_robots_count\n"})})]}),"\n",(0,t.jsx)(n.h3,{id:"\u5EF6\u4F38\u95EE\u9898",children:"\u5EF6\u4F38\u95EE\u9898"}),"\n",(0,t.jsxs)(n.p,{children:["\u56DE\u8FC7\u5934\u770B \u9898\u76EE\u90A3\u53E5\u5FC5\u987B ",(0,t.jsx)(n.strong,{children:"\u8FDE\u7EED\u53D6\u673A\u5668\u4EBA"})," \u7684\u53D9\u8FF0 \u5404\u4F4D\u89C9\u5F97\u662F\u6761\u7F57\u55E6\u9650\u5236 \u8FD8\u662F\u5176\u5B9E\u662F\u4EE3\u7801\u80FD\u6781\u901F\u5316\u7684\u6838\u5FC3\u5462\u{1F913}"]})]})}function m(e={}){let{wrapper:n}={...(0,i.R)(),...e.components};return n?(0,t.jsx)(n,{...e,children:(0,t.jsx)(x,{...e})}):x(e)}},7413(e,n,s){s.d(n,{A:()=>r});let r=s.p+"assets/images/2398_efficiency-d925a4c60c5deb29a9affd3dde2987c4.png"},7250(e,n,s){s.d(n,{A:()=>d});var r=s(4848);s(6540);var t=s(4164),i=s(7663);function a({children:e,className:n,hidden:s}){return(0,r.jsx)("div",{role:"tabpanel",className:(0,t.A)("tabItem_Ymn6",n),hidden:s,children:e})}function d({children:e,className:n,value:s}){let{selectedValue:t,lazy:l}=(0,i.uc)(),o=s===t;return!o&&l?null:(0,r.jsx)(a,{className:n,hidden:!o,children:e})}},773(e,n,s){s.d(n,{A:()=>u});var r=s(4848);s(6540);var t=s(4164),i=s(8287),a=s(7663),d=s(8584),l=s(9863);function o({className:e}){let{selectedValue:n,selectValue:s,tabValues:i,block:l}=(0,a.uc)(),c=[],{blockElementScrollPositionUntilNextRender:h}=(0,d.a_)(),u=e=>{let r=e.currentTarget,t=i[c.indexOf(r)].value;t!==n&&(h(r),s(t))},x=e=>{let n=null;switch(e.key){case"Enter":u(e);break;case"ArrowRight":{let s=c.indexOf(e.currentTarget)+1;n=c[s]??c[0];break}case"ArrowLeft":{let s=c.indexOf(e.currentTarget)-1;n=c[s]??c[c.length-1]}}n?.focus()};return(0,r.jsx)("ul",{role:"tablist","aria-orientation":"horizontal",className:(0,t.A)("tabs",{"tabs--block":l},e),